#include <stdio.h>
#include <stdlib.h>

typedef struct FileHandle {
    FILE *file;
    struct FileHandle *next;
} FileHandle;

typedef struct {
    FileHandle *head;
} FileHandleList;

FileHandleList* createList() {
    FileHandleList *list = (FileHandleList*)malloc(sizeof(FileHandleList));
    list->head = NULL;
    return list;
}

int addFileHandle(FileHandleList *list, const char *filename, const char *mode) {
    FILE *file = fopen(filename, mode);
    if (!file) {
        return -1; // Failed to open file
    }
    FileHandle *newHandle = (FileHandle*)malloc(sizeof(FileHandle));
    newHandle->file = file;
    newHandle->next = list->head;
    list->head = newHandle;
    return 0; // Success
}

int removeFileHandle(FileHandleList *list, FILE *file) {
    FileHandle **current = &(list->head);
    while (*current) {
        if ((*current)->file == file) {
            FileHandle *toRemove = *current;
            *current = toRemove->next;
            fclose(toRemove->file);
            free(toRemove);
            return 0; // Success
        }
        current = &((*current)->next);
    }
    return -1; // Not found
}

void cleanupFileHandleList(FileHandleList *list) {
    FileHandle *current = list->head;
    while (current) {
        FileHandle *toFree = current;
        current = current->next;
        fclose(toFree->file);
        free(toFree);
    }
    list->head = NULL; // Safe cleanup
}

void destroyList(FileHandleList *list) {
    cleanupFileHandleList(list);
    free(list);
}